(function(){if(document.getElementById("agilo-chat-styles"))return;const s=document.createElement("style");s.id="agilo-chat-styles";s.textContent="/* ===========================================================\n   CHAT / MESSAGES — Design system Agilotext + Webflow\n   ------------------------------------------------------------\n   · Jetons côté page (Webflow) : --color--blue, --color--gris,\n     --color--gris_foncé, --color--blanc_gris, --color--noir_25,\n     --color--white, --0-5_radius, etc.\n   · Jetons d’enrichissement (optionnels) : --agilo-primary, --agilo-surface,\n     --agilo-text, --agilo-dim, --agilo-border, --agilo-shadow, --agilo-focus\n   · Inspiration patterns (awesome-design / Intercom, Linear) : espacement\n     4–8px sur les contrôles, focus :focus-visible, ombre légère sur cartes.\n   Toute couleur de secours (fallback hex) s’applique si la variable absente.\n   =========================================================== */\n\n/* Onglets éditeur (main + data-ed-tabs) : un seul volet visible.\n   - [hidden] peut être perdu ou surchargé par un style Webflow (!important sur .edtr-pane, flex, etc.)\n   - Le script des onglets ne met .is-active que sur le volet courant → filet de secours */\nsection.edtr-pane[hidden],\nmain.ed-main [role=\"tabpanel\"].edtr-pane:not(.is-active),\n.ed-main[data-ed-tabs] [role=\"tabpanel\"].edtr-pane:not(.is-active) {\n  display: none !important;\n}\n\n/* Conteneur */\n#chatView{\n  display:flex;\n  flex-direction:column;\n  gap: .9rem;\n  padding: .25rem 0;\n  overflow:auto;\n}\n\n/* Bouton occupé */\n#btnAsk.is-busy{ opacity:.65; pointer-events:none; }\n\n/* Message (conteneur) */\n.msg{\n  display:flex;\n  flex-direction:column;\n  max-width:72ch;\n  animation: chat-slide-in .28s ease-out;\n}\n.msg--user{ align-self:flex-end; }\n.msg--ai{   align-self:flex-start; }\n.msg--sys{  align-self:center; opacity:.85; }\n\n/* Petite meta (auteur/heure) */\n.msg-meta{\n  font:600 .72rem/1.2 system-ui,-apple-system,Segoe UI,Roboto;\n  color: var(--agilo-dim, var(--color--gris, #525252));\n  margin: 0 0 .35rem;\n}\n\n/* Bulle */\n.msg-bubble{\n  padding: .85rem 1rem;\n  border-radius: var(--0-5_radius, .5rem);\n  background: var(--agilo-surface-2, var(--color--blanc_gris, #f8f9fa));\n  color: var(--agilo-text, var(--color--gris_foncé, #020202));\n  border: 1px solid var(--agilo-border, var(--color--noir_25, #343a4040));\n  box-shadow: var(--agilo-shadow, 0 1px 2px rgba(0,0,0,.08), 0 4px 10px rgba(0,0,0,.06));\n  white-space: normal;\n  line-height: 1.6;\n}\n\n/* Bulle “user” en primaire (contraste AA) */\n.msg--user .msg-bubble{\n  background: var(--agilo-primary, var(--color--blue, #174a96));\n  color: var(--color--white, #fff);\n  border-color: transparent;\n}\n\n/* ===== BLOC EMAIL (type ChatGPT) ===== */\n.msg-bubble--email {\n  padding: 0;\n  overflow: hidden;\n  max-width: 100%;\n}\n\n.agilo-email-block {\n  width: 100%;\n  border-radius: var(--0-5_radius, .5rem);\n  background: var(--agilo-surface-2, var(--color--blanc_gris, #f8f9fa));\n  border: 1px solid var(--agilo-border, var(--color--noir_25, #343a4040));\n  box-shadow: 0 1px 3px rgba(0,0,0,.07), 0 4px 12px rgba(0,0,0,.05);\n  overflow: hidden;\n}\n\n.agilo-email-block-header {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  gap: .5rem;\n  padding: .5rem .75rem;\n  background: color-mix(in srgb, var(--agilo-text, #0b1222) 4%, var(--agilo-surface-2, #f8f9fa));\n  border-bottom: 1px solid var(--agilo-border, #343a4040);\n  flex-wrap: wrap;\n}\n\n.agilo-email-block-label {\n  font: 600 .8rem/1.2 system-ui, -apple-system, Segoe UI, Roboto;\n  color: var(--agilo-dim, var(--color--gris, #525252));\n}\n\n.agilo-email-block-tools {\n  display: flex;\n  align-items: center;\n  gap: .25rem;\n}\n\n/* Boutons icon-only style ChatGPT (Copy + Open in app) */\n.agilo-email-btn {\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  gap: .25rem;\n  width: 2rem;\n  height: 2rem;\n  padding: 0;\n  border: none;\n  border-radius: .375rem;\n  background: transparent;\n  color: var(--agilo-dim, var(--color--gris, #6b7280));\n  cursor: pointer;\n  text-decoration: none;\n  transition: color .15s, background .15s, transform .15s;\n}\n\n.agilo-email-btn:hover {\n  color: var(--agilo-text, var(--color--gris_foncé, #020202));\n  background: color-mix(in srgb, var(--agilo-text, #0b1222) 6%, transparent);\n}\n\n.agilo-email-btn:focus-visible {\n  outline: 2px solid color-mix(in srgb, var(--agilo-primary) 60%, transparent);\n  outline-offset: 2px;\n}\n\n.agilo-email-btn .agilo-email-icon {\n  flex-shrink: 0;\n}\n\n/* Bouton \"Open in app\" + dropdown (style ChatGPT) */\n.agilo-email-open-wrap {\n  position: relative;\n  display: inline-flex;\n}\n\n.agilo-email-btn-open .agilo-email-icon,\n.agilo-email-btn-open .agilo-email-send-icon {\n  color: var(--agilo-dim, #6b7280);\n}\n\n.agilo-email-btn-open:hover .agilo-email-icon,\n.agilo-email-btn-open:hover .agilo-email-send-icon {\n  color: var(--agilo-text, #020202);\n}\n\n.agilo-email-dropdown {\n  position: absolute;\n  top: 100%;\n  right: 0;\n  margin-top: 4px;\n  min-width: 180px;\n  padding: 6px;\n  border-radius: 8px;\n  background: var(--agilo-surface, var(--color--white, #fff));\n  border: 1px solid var(--agilo-border, var(--color--noir_25, #343a4040));\n  box-shadow: 0 2px 8px rgba(0,0,0,.08);\n  z-index: 100;\n  list-style: none;\n}\n\n.agilo-email-dropdown[hidden] {\n  display: none;\n}\n\n.agilo-email-dropdown-item {\n  display: flex;\n  align-items: center;\n  gap: 10px;\n  width: 100%;\n  padding: 8px 10px;\n  border: none;\n  border-radius: 6px;\n  background: transparent;\n  color: var(--agilo-text, var(--color--gris_foncé, #020202));\n  font: 500 .8125rem/1.3 system-ui, -apple-system, Segoe UI, Roboto;\n  text-decoration: none;\n  cursor: pointer;\n  transition: background .12s;\n  text-align: left;\n}\n\n.agilo-email-dropdown-item:hover {\n  background: color-mix(in srgb, var(--agilo-text, #0b1222) 6%, var(--agilo-surface-2, #f8f9fa));\n  color: var(--agilo-text, #020202);\n}\n\n.agilo-email-dropdown-icon {\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  width: 20px;\n  height: 20px;\n  flex-shrink: 0;\n}\n\n.agilo-email-dropdown-icon svg,\n.agilo-email-dropdown-icon img {\n  width: 20px;\n  height: 20px;\n  display: block;\n  object-fit: contain;\n}\n\n.agilo-email-dropdown-icon .agilo-email-logo-default {\n  color: var(--agilo-text, var(--color--gris_foncé, #020202));\n}\n\n.agilo-email-btn-copy.agilo-email-btn-copied {\n  color: var(--agilo-text, #020202);\n  background: color-mix(in srgb, var(--agilo-text, #0b1222) 8%, transparent);\n  transform: scale(1.05);\n}\n\n.agilo-email-block-subject {\n  padding: .5rem .75rem;\n  font: 600 .85rem/1.3 system-ui, -apple-system, Segoe UI, Roboto;\n  color: var(--agilo-text, var(--color--gris_foncé, #020202));\n  border-bottom: 1px solid var(--agilo-border, #343a4040);\n}\n\n.agilo-email-block-subject-label {\n  color: var(--agilo-dim, var(--color--gris, #525252));\n  font-weight: 500;\n  margin-right: .35rem;\n}\n\n.agilo-email-block-body {\n  padding: 1rem 1.1rem;\n  font-size: .9rem;\n  color: var(--agilo-text, var(--color--gris_foncé, #020202));\n  word-break: break-word;\n  line-height: 1.7;\n  max-height: 50vh;\n  overflow-y: auto;\n}\n\n.agilo-email-block-body .agilo-email-p {\n  margin: 0 0 1.35em;\n}\n\n.agilo-email-block-body .agilo-email-p:last-child {\n  margin-bottom: 0;\n}\n\n.agilo-email-block-body .agilo-email-p-first {\n  font-weight: 600;\n  color: var(--agilo-text, #020202);\n}\n\n/* Bloc \"Ci-dessous\" (commentaire interne) */\n.agilo-email-internal-comment {\n  margin-top: 0;\n  padding: .6rem 1rem .75rem;\n  border-top: 1px solid var(--agilo-border, #343a4040);\n  background: color-mix(in srgb, var(--agilo-text, #0b1222) 3%, var(--agilo-surface-2, #f8f9fa));\n}\n\n.agilo-email-ci-dessous {\n  display: flex;\n  align-items: center;\n  gap: .4rem;\n  font: 600 .75rem/1.2 system-ui, -apple-system, Segoe UI, Roboto;\n  color: var(--agilo-dim, var(--color--gris, #525252));\n  margin-bottom: .35rem;\n}\n\n.agilo-email-ci-dessous svg {\n  flex-shrink: 0;\n  color: var(--agilo-dim, #525252);\n}\n\n.agilo-email-internal-comment-text {\n  font-size: .85rem;\n  line-height: 1.5;\n  color: var(--agilo-text, var(--color--gris_foncé, #020202));\n}\n\n/* Typo/rendu Markdown générique (sans wrapper .prose) */\n.msg-bubble h1,.msg-bubble h2,.msg-bubble h3{\n  margin:.8em 0 .4em; font-weight:700; line-height:1.3;\n}\n.msg-bubble h1{ font-size:1.5em; }\n.msg-bubble h2{ font-size:1.25em; }\n.msg-bubble h3{ font-size:1.05em; }\n.msg-bubble p{ margin:.45em 0; }\n.msg-bubble ul,.msg-bubble ol{ margin:.35em 0 .6em 1.25em; padding:0; }\n.msg-bubble li{ margin:.15em 0; }\n.msg-bubble hr{\n  border:0; margin:.6em 0;\n  border-top:1px solid var(--agilo-divider, color-mix(in srgb, var(--agilo-text, #0b1222) 14%, transparent));\n}\n.msg-bubble a{\n  color: var(--agilo-primary, var(--color--blue, #174a96));\n  text-decoration: underline;\n}\n.msg-bubble blockquote{\n  margin:.6em 0; padding:.45em .8em; border-radius:.35rem;\n  border-left:3px solid var(--agilo-primary, var(--color--blue, #174a96));\n  background: color-mix(in srgb,\n              var(--agilo-primary, var(--color--blue, #174a96)) 6%,\n              var(--agilo-surface-2, var(--color--blanc_gris, #f8f9fa)));\n}\n.msg-bubble code{\n  font-family: ui-monospace, Menlo, monospace;\n  background: color-mix(in srgb,\n              var(--agilo-text, var(--color--gris_foncé, #020202)) 8%,\n              var(--agilo-surface, var(--color--white, #fff)));\n  padding:.05em .35em; border-radius:.3em;\n}\n.msg-bubble pre{\n  background: color-mix(in srgb,\n              var(--agilo-text, var(--color--gris_foncé, #020202)) 92%,\n              var(--agilo-surface, var(--color--white, #fff)));\n  color: var(--color--white, #fff);\n  padding:.7em .85em; border-radius: var(--0-5_radius, .5rem);\n  overflow:auto;\n}\n.msg-bubble pre code{ background:transparent; padding:0; }\n\n/* Barre d'actions sous la bulle (copier, export…) */\n.msg-actions,\n.msg-tools{\n  display:flex;\n  flex-wrap:wrap;\n  gap:.4rem;\n  margin:.45rem 0 0;\n  padding-top:.55rem;\n  border-top:1px solid var(--agilo-border, var(--color--noir_25, #343a4040));\n}\n.msg-action-btn{\n  appearance:none;\n  cursor:pointer;\n  user-select:none;\n  display: inline-flex;\n  align-items: center;\n  gap: .35rem;\n  border:1px solid var(--agilo-border, var(--color--noir_25, #343a4040));\n  background: var(--agilo-surface-2, var(--color--blanc_gris, #f8f9fa));\n  color: var(--agilo-text, var(--color--gris_foncé, #020202));\n  padding:.36rem .6rem;\n  border-radius:.45rem;\n  font:600 .78rem/1 system-ui,-apple-system,Segoe UI,Roboto;\n  transition: background .15s, transform .06s, color .15s, border-color .15s;\n}\n.msg-action-btn:hover{\n  background: color-mix(in srgb,\n              var(--agilo-surface-2, var(--color--blanc_gris, #f8f9fa)) 70%,\n              var(--agilo-primary, var(--color--blue, #174a96)) 30%);\n  color: var(--color--white, #fff);\n  border-color: transparent;\n}\n.msg-action-btn:active{ transform: translateY(.0625rem); }\n.msg-action-btn:focus-visible{\n  outline: var(--agilo-focus, 2px solid color-mix(in srgb, var(--agilo-primary) 70%, transparent));\n  outline-offset: 2px;\n}\n.msg-action-btn[disabled]{ opacity:.6; cursor:not-allowed; }\n\n.msg-action-copy-copied {\n  background: color-mix(in srgb, var(--agilo-text, #0b1222) 8%, var(--agilo-surface-2, #f8f9fa)) !important;\n  color: var(--agilo-text, #020202) !important;\n  border-color: var(--agilo-border, rgba(0,0,0,.15)) !important;\n}\n\n/* Barre d'actions bas-droite sur les bulles utilisateur (copy + éditer) */\n.msg-user-actions {\n  display: flex;\n  justify-content: flex-end;\n  gap: .25rem;\n  margin: .25rem 0 0;\n  padding-top: .3rem;\n}\n.msg-user-action-btn {\n  appearance: none;\n  cursor: pointer;\n  user-select: none;\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  width: 26px;\n  height: 26px;\n  border: none;\n  background: transparent;\n  /* Sur bulle bleue : icônes lisibles (ne pas utiliser gris \"muted\" du thème clair) */\n  color: color-mix(in srgb, var(--color--white, #fff) 70%, transparent);\n  border-radius: var(--0-5_radius, .4rem);\n  padding: 0;\n  transition: background .12s, color .12s, transform .06s;\n  opacity: 0;\n}\n/* Révéler au survol de la bulle */\n.msg--user:hover .msg-user-action-btn,\n.msg--user:focus-within .msg-user-action-btn {\n  opacity: 1;\n}\n.msg-user-action-btn:hover {\n  background: color-mix(in srgb, var(--color--white, #fff) 18%, transparent);\n  color: var(--color--white, #fff);\n}\n.msg-user-action-btn:active { transform: translateY(1px); }\n.msg-user-action-btn:focus-visible {\n  outline: 2px solid var(--agilo-focus, color-mix(in srgb, var(--agilo-primary, var(--color--blue, #174a96)) 55%, #fff));\n  outline-offset: 2px;\n  opacity: 1;\n}\n\n/* Zone de saisie d'édition : à l'intérieur de la bulle, même rendu visuel (bleu) */\n.msg--user .msg-bubble.msg-bubble--editing {\n  display: block;\n  padding: .65rem .85rem;\n  min-width: 8ch;\n}\n.msg--user .msg-bubble .msg-bubble-edit-ta {\n  display: block;\n  width: 100%;\n  min-width: 0;\n  box-sizing: border-box;\n  margin: 0;\n  border: 1px solid rgba(255,255,255,.4);\n  border-radius: .4rem;\n  background: rgba(0,0,0,.1);\n  color: #fff;\n  font: inherit;\n  line-height: 1.5;\n  resize: vertical;\n  min-height: 2.5em;\n  padding: .35rem .5rem;\n  outline: none;\n}\n.msg--user .msg-bubble .msg-bubble-edit-ta::placeholder { color: rgba(255,255,255,.55); }\n.msg--user .msg-bubble .msg-bubble-edit-ta:focus {\n  border-color: rgba(255,255,255,.75);\n  background: rgba(0,0,0,.12);\n}\n\n/* Barre Annuler / Enregistrer sous la bulle éditée */\n.agilo-user-edit-bar {\n  display: flex;\n  justify-content: flex-end;\n  gap: .5rem;\n  margin-top: .45rem;\n  flex-wrap: wrap;\n}\n.agilo-user-edit-cancel {\n  appearance: none;\n  cursor: pointer;\n  padding: .35rem .75rem;\n  border-radius: var(--0-5_radius, .5rem);\n  border: 1px solid var(--agilo-border, var(--color--noir_25, #343a4040));\n  background: var(--agilo-surface, var(--color--white, #fff));\n  color: var(--agilo-dim, var(--color--gris, #525252));\n  font-size: .82rem;\n  font-family: inherit;\n  font-weight: 500;\n  transition: background .12s, border-color .12s, color .12s;\n}\n.agilo-user-edit-cancel:hover {\n  background: var(--agilo-surface-2, var(--color--blanc_gris, #f8f9fa));\n  color: var(--agilo-text, var(--color--gris_foncé, #020202));\n}\n.agilo-user-edit-send {\n  appearance: none;\n  cursor: pointer;\n  padding: .35rem .85rem;\n  border-radius: var(--0-5_radius, .5rem);\n  border: none;\n  background: var(--agilo-primary, var(--color--blue, #174a96));\n  color: var(--color--white, #fff);\n  font-size: .82rem;\n  font-weight: 600;\n  font-family: inherit;\n  transition: background .12s, filter .12s;\n}\n.agilo-user-edit-send:hover {\n  background: color-mix(in srgb, var(--agilo-primary, var(--color--blue, #174a96)) 88%, #000);\n  filter: contrast(1.02);\n}\n.agilo-user-edit-send:focus-visible,\n.agilo-user-edit-cancel:focus-visible {\n  outline: 2px solid var(--agilo-focus, color-mix(in srgb, var(--agilo-primary, var(--color--blue, #174a96)) 50%, transparent));\n  outline-offset: 2px;\n}\n\n/* Titres manquants (tu n'as que h1–h3 aujourd'hui) */\n.msg-bubble h4,.msg-bubble h5,.msg-bubble h6{\n  margin:.65em 0 .35em; font-weight:700; line-height:1.3;\n}\n.msg-bubble h4{ font-size:1.0em; }\n.msg-bubble h5{ font-size:.95em; }\n.msg-bubble h6{ font-size:.9em; }\n\n/* Tables Markdown (rend .md-table propre sans toucher le reste) */\n.msg-bubble table.md-table{\n  width:100%; border-collapse:collapse;\n  margin:.55em 0 .85em; font-size:.95em;\n  border:1px solid var(--agilo-border, var(--color--noir_25, #343a4040));\n}\n.msg-bubble .md-table th,\n.msg-bubble .md-table td{\n  padding:.45em .6em; vertical-align:top;\n  border:1px solid var(--agilo-border, var(--color--noir_25, #343a4040));\n}\n.msg-bubble .md-table thead th{\n  background: color-mix(in srgb,\n              var(--agilo-primary, var(--color--blue, #174a96)) 6%,\n              var(--agilo-surface-2, var(--color--blanc_gris, #f8f9fa)));\n  font-weight:700;\n}\n.msg-bubble .md-table tbody tr:nth-child(odd){\n  background: color-mix(in srgb,\n              var(--agilo-text, var(--color--gris_foncé, #020202)) 3%,\n              var(--agilo-surface-2, var(--color--blanc_gris, #f8f9fa)));\n}\n\n/* Sous-listes un peu plus compactes (complément, ne remplace rien) */\n.msg-bubble ul ul,\n.msg-bubble ol ol{ margin:.25em 0 .5em 1.25em; }\n\n/* Cases à cocher dans les listes */\n.msg-bubble li input[type=\"checkbox\"]{\n  margin-right:.35em; transform:translateY(2px);\n}\n\n/* (Optionnel) Boutons timecode que tu insères dans le HTML */\n.msg-bubble .agilo-tc{\n  display:inline-flex; align-items:center; gap:.25rem;\n  border:1px solid var(--agilo-border, var(--color--noir_25, #343a4040));\n  background: var(--agilo-surface-2, var(--color--blanc_gris, #f8f9fa));\n  color: var(--agilo-text, var(--color--gris_foncé, #020202));\n  padding:.08rem .35rem; border-radius:.35rem;\n  font:600 .78rem/1 system-ui,-apple-system,Segoe UI,Roboto; cursor:pointer;\n}\n.msg-bubble .agilo-tc:hover{\n  background: color-mix(in srgb,\n              var(--agilo-surface-2, #f8f9fa) 70%,\n              var(--agilo-primary, #174a96) 30%);\n  color:#fff; border-color:transparent;\n}\n/* Sous-listes rendues comme imbriquées même si le HTML est \"à plat\" */\n.msg-bubble li + ul,\n.msg-bubble li + ol{\n  margin-top:.25em;\n  margin-bottom:.5em;\n  margin-left:1.25em;\n}\n\n/* Citations : micro-rythme du texte interne */\n.msg-bubble blockquote p{ margin:.25em 0; }\n\n/* ===== INDICATEUR \"THINKING\" CHATGPT-STYLE ===== */\n.thinking-indicator {\n  display: inline-flex;\n  align-items: center;\n  gap: 8px;\n  color: var(--color--gris, #6b7280);\n  font-weight: 500;\n  font-size: 14px;\n}\n\n.thinking-dots {\n  display: inline-flex;\n  gap: 4px;\n}\n\n.thinking-dot {\n  width: 6px;\n  height: 6px;\n  border-radius: 50%;\n  background: var(--color--gris, #6b7280);\n  animation: thinking-pulse 1.4s ease-in-out infinite;\n}\n\n.thinking-dot:nth-child(1) { animation-delay: 0s; }\n.thinking-dot:nth-child(2) { animation-delay: 0.2s; }\n.thinking-dot:nth-child(3) { animation-delay: 0.4s; }\n\n@keyframes thinking-pulse {\n  0%, 60%, 100% {\n    opacity: 0.3;\n    transform: scale(0.8);\n  }\n  30% {\n    opacity: 1;\n    transform: scale(1);\n  }\n}\n\n/* Animation d'apparition */\n.thinking-indicator {\n  animation: thinking-fade-in 0.3s ease-out;\n}\n\n@keyframes thinking-fade-in {\n  from {\n    opacity: 0;\n    transform: translateY(10px);\n  }\n  to {\n    opacity: 1;\n    transform: translateY(0);\n  }\n}\n\n/* Petite animation d'arrivée */\n@keyframes chat-slide-in{\n  from{ opacity:0; transform:translateY(10px); }\n  to{   opacity:1; transform:translateY(0); }\n}\n\n/* Responsive */\n@media (max-width: 40rem){\n  #chatView{ gap: .7rem; }\n  .msg-bubble{ padding:.75rem .85rem; }\n  .msg-bubble--email { padding: 0; }\n  .msg-actions .msg-action-btn{ font-size:.74rem; }\n  .agilo-email-block-header { padding: .45rem .6rem; }\n  .agilo-email-block-body { padding: .6rem .75rem; max-height: 40vh; }\n}\n\n/* Respecte \"réduire les animations\" */\n@media (prefers-reduced-motion: reduce){\n  *{ animation-duration:.001ms !important; animation-iteration-count:1 !important; transition:none !important; }\n}\n\n/* ===== BARRE DE COMPOSITION (V07 — CSS métier uniquement) =====\n   Le layout visuel (flex, dimensions, boutons) est désormais dans\n   chat-submission-embed.html (copié dans l'Embed Webflow).\n   Ce bloc ne contient que les états fonctionnels partagés :\n   busy, recording, badge, masquage #btnAsk. */\n\n/* Busy — bulle grisée pendant l'envoi */\n#chat-send-btn.is-busy,\n.agilo-chat-send.is-busy { opacity: .45; pointer-events: none; }\n\n/* Mic — état enregistrement */\n#chat-dictate-btn.is-recording { color: #ef4444; animation: mic-pulse 1.2s ease-in-out infinite; }\n@keyframes mic-pulse {\n  0%, 100% { background: transparent; }\n  50%       { background: rgba(239,68,68,.12); }\n}\n\n/* Masquer l'ancien div#btnAsk Webflow en toutes circonstances */\n#btnAsk[hidden] { display: none !important; }\n#chat-compose-footer:has(#chat-send-btn) #btnAsk { display: none !important; }\n\n/* Zone embed Webflow : pas de 2e cadre autour du HTML injecté */\n.w-embed:has(#agilo-chat-submission),\ndiv.w-embed:has(#agilo-chat-submission) {\n  border: none !important;\n  box-shadow: none !important;\n  background: transparent !important;\n  padding: 0 !important;\n  margin: 0 !important;\n  display: block !important;\n}\n\n/* Bordure unique sur #agilo-chat-submission (même chaine que l’embed inline) */\n#agilo-chat-submission {\n  position: relative;\n  box-sizing: border-box;\n  font-family: inherit; /* hérite Montserrat/Inter de la page Webflow */\n  border: 1px solid var(--agilo-border, var(--color--noir_25, #343a4040));\n  border-radius: var(--0-5_radius, .75rem);\n  background: var(--agilo-surface, var(--color--white, #fff));\n  color: var(--agilo-text, var(--color--gris_foncé, #020202));\n  box-shadow: var(--agilo-shadow, 0 1px 3px rgba(0,0,0,.07), 0 1px 2px rgba(0,0,0,.04));\n  overflow: hidden;\n  transition: box-shadow .2s, border-color .2s;\n}\n#agilo-chat-submission:focus-within {\n  border-color: color-mix(in srgb, var(--agilo-primary, var(--color--blue, #174a96)) 40%, var(--agilo-border, var(--color--noir_25, #343a4040)));\n  box-shadow: var(--agilo-shadow, 0 1px 3px rgba(0,0,0,.07)), 0 0 0 3px color-mix(in srgb, var(--agilo-primary, var(--color--blue, #174a96)) 14%, transparent);\n}\n#agilo-chat-submission #chat-compose-bar {\n  border: none;\n  box-shadow: none;\n  position: relative;\n  background: transparent;\n}\n#agilo-chat-submission #chat-compose-footer {\n  border: none;\n  border-top: 1px solid var(--agilo-border, var(--color--noir_25, #343a4040));\n  background: color-mix(in srgb, var(--agilo-surface, var(--color--white, #fff)) 96%, var(--agilo-surface-2, var(--color--blanc_gris, #f6f6f6)));\n  flex-wrap: nowrap;\n}\n/* Badge file : pas de bandeau jaune; dans la barre, coin haut-droit (voir aussi embed) */\n#agilo-chat-submission #chat-queue-badge[hidden],\n#agilo-chat-submission #chat-queue-badge:empty {\n  display: none !important;\n  margin: 0 !important;\n  padding: 0 !important;\n  min-width: 0 !important;\n  background: transparent !important;\n}\n#agilo-chat-submission #chat-queue-badge:not([hidden]) {\n  position: absolute;\n  z-index: 2;\n  top: .4rem;\n  right: .55rem;\n  margin: 0;\n  padding: 2px 7px;\n  min-width: 1.1rem;\n  border-radius: var(--0-5_radius, 6px);\n  /* file d'attente : teinte chaude, texte ambre fonce (fallback) */\n  background: color-mix(in srgb, #b45309 11%, var(--agilo-surface, var(--color--white, #fff)));\n  color: #92400e;\n  font-size: .7rem;\n  font-weight: 600;\n  line-height: 1.2;\n  pointer-events: none;\n  box-shadow: 0 1px 2px color-mix(in srgb, var(--agilo-text, #0b1222) 6%, transparent);\n  border: 1px solid color-mix(in srgb, #b45309 25%, var(--agilo-surface, var(--color--white, #fff)));\n}\n\n/* Mode JS-build fallback — barre inline unique (même jetons que l’embed Webflow) */\nbody:not(:has(#agilo-chat-submission)) #chat-compose-bar {\n  display: flex;\n  flex-direction: row;\n  align-items: flex-end;\n  gap: .2rem;\n  padding: .4rem .45rem;\n  width: 100%;\n  box-sizing: border-box;\n  font-family: inherit;\n  border: 1px solid var(--agilo-border, var(--color--noir_25, #343a4040));\n  border-radius: var(--0-5_radius, .75rem);\n  background: var(--agilo-surface, var(--color--white, #fff));\n  color: var(--agilo-text, var(--color--gris_foncé, #020202));\n  box-shadow: var(--agilo-shadow, 0 1px 3px rgba(0,0,0,.07), 0 1px 2px rgba(0,0,0,.04));\n  overflow: hidden;\n  transition: box-shadow .2s, border-color .2s;\n  position: relative;\n}\nbody:not(:has(#agilo-chat-submission)) #chat-compose-bar:focus-within {\n  border-color: color-mix(in srgb, var(--agilo-primary, var(--color--blue, #174a96)) 40%, var(--agilo-border, var(--color--noir_25, #343a4040)));\n  box-shadow: var(--agilo-shadow, 0 1px 3px rgba(0,0,0,.07)), 0 0 0 3px color-mix(in srgb, var(--agilo-primary, var(--color--blue, #174a96)) 14%, transparent);\n}\nbody:not(:has(#agilo-chat-submission)) #chatPrompt {\n  flex: 1 1 0; min-width: 0;\n  border: none; outline: none; box-shadow: none; background: transparent; resize: none;\n  min-height: 36px; max-height: 180px; padding: .45rem .3rem;\n  font-size: .9375rem; line-height: 1.5; color: var(--agilo-text, #020202);\n  align-self: center;\n}\nbody:not(:has(#agilo-chat-submission)) #chat-attach-btn,\nbody:not(:has(#agilo-chat-submission)) #chat-dictate-btn,\nbody:not(:has(#agilo-chat-submission)) #chat-send-btn {\n  display: inline-flex; align-items: center; justify-content: center; flex-shrink: 0;\n  width: 2rem; height: 2rem; border-radius: 50%; border: none; background: transparent;\n  cursor: pointer; color: var(--agilo-dim, #6b7280); padding: 0;\n  transition: background .14s, color .14s; box-sizing: border-box; font-size: 0;\n}\nbody:not(:has(#agilo-chat-submission)) #chat-attach-btn { opacity: .5; }\nbody:not(:has(#agilo-chat-submission)) #chat-attach-btn:hover { background: color-mix(in srgb, var(--agilo-text, #0b1222) 7%, transparent); opacity: .8; }\nbody:not(:has(#agilo-chat-submission)) #chat-send-btn { color: var(--agilo-primary, var(--color--blue, #174a96)); }\nbody:not(:has(#agilo-chat-submission)) #chat-send-btn:hover { background: color-mix(in srgb, var(--agilo-primary, var(--color--blue, #174a96)) 10%, transparent); }\n\n@media (max-width: 40rem) {\n  body:not(:has(#agilo-chat-submission)) #chat-compose-bar { border-radius: var(--0-5_radius, .55rem); padding: .3rem .35rem; }\n  body:not(:has(#agilo-chat-submission)) #chatPrompt { font-size: .9rem; }\n}\n";document.head.appendChild(s);})();